export default {
  props: {
    custom: Boolean,
    summoner: Object
  },
  mounted() {
    console.log(this.summoner);
  },
  methods: {
    getSummonerIconUrl() {
      const {
        host,
        port
      } = this.$store.state.config.download;
      return `${host}:${port}/summoner_icons/${this.summoner.summonerIconId}.png`;
    },
    isCaptain() {
      return this.summoner.summonerName == this.$store.state.lobby.owner.summonerName;
    },
    canKick() {
      return this.$store.state.lobbyOwner && this.summoner.summonerName != this.$store.state.user.summonerName;
    },
    isFriend() {
      if (this.summoner.summonerName == this.$store.state.user.summonerName) {
        return true;
      }
      return this.$store.state.friendList.filter(friend => {
        return friend.summonerName == this.summoner.summonerName;
      }).length > 0;
    },
    addFriend() {
      this.$socket.sendSystemMessage("FRIEND_OUT", {
        data: this.summoner.summonerName
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
      });
    },
    kickUser() {
      this.$socket.sendLobbyMessage("LOBBY_KICK", {
        data: this.summoner.summonerName
      }, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
      });
    }
  }
};
